#!/usr/bin/env python3
"""
Deuteronomy ch32-34 mkt-original gap-fill.
Ch32: Song of Moses (Ha'azinu) — cosmic witness, YHWH's care for Israel,
      Israel's apostasy, judgment and ultimate redemption.
Ch33: Moses's tribal blessing — echoes of Jacob's blessing in Gen 49.
Ch34: Moses's death on Nebo — end of the Mosaic era.
"""
import json, pathlib

DATA = {
    "32": {
        "1": "<p><strong>haʾăzînû haššāmayim vaʾădabbērāh</strong> — 'Give ear, O heavens, and I will speak.' The Song of Moses opens with a cosmic courtroom summons: <em>šāmayim</em> (heavens) and <em>ʾārets</em> (earth) are called as witnesses, echoing the covenant lawsuit formula (<em>rîḇ</em>) established in Deut 4:26; 30:19; 31:28. The Hebrew root <em>ʾāzan</em> (H238 — to give ear, incline the ear) is the verb for attentive listening demanded in legal settings. The invocation of heaven and earth as witnesses was standard in ancient Near Eastern treaty texts — Israel's covenant with YHWH had cosmic witnesses. When Israel broke the covenant, those witnesses would testify against them (cf. Isa 1:2 which opens identically).</p>",
        "2": "<p><strong>yaarof kammāṭār liqqḥî tizzal kattāl ʾimrāṯî</strong> — 'Let my teaching drop as the rain, my speech distill as the dew.' The rain-metaphor for Torah (<em>liqaḥ</em> — H3948, teaching, that which is received) is significant: rain (<em>māṭār</em>) and dew (<em>ṭal</em>) fall gently but penetrate and transform. The word <em>ʾimrāṯî</em> (my word/utterance — from <em>ʾĕmāh</em>) is the root of the exclamation <em>ʾămir</em> in Isa 5:1 (a song). The comparison to <em>śeʿîrîm</em> (light rain/showers on grass) and <em>reḇîḇîm</em> (thundershowers on vegetation) pairs gentleness with power. The word that Israel was asked to hear was not harsh law but life-giving instruction — as necessary as rain for the land.</p>",
        "3": "<p><strong>kî šem YHWH ʾeqrāʾ hāḇû gōdel lēʾlōhênû</strong> — 'For I call on the name of YHWH; ascribe greatness to our God.' The preposition for proclaiming the divine name is <em>qārāʾ bešēm YHWH</em> (to call in/on the Name) — the same phrase for the patriarchal liturgical worship at altars (Gen 12:8; 13:4; 26:25). Moses calls on the Name to inaugurate the song. <em>Hāḇû gōdel lēʾlōhênû</em> (ascribe/give greatness to our God — H1433 gōdel from H1431 gādal, to be great) is a summons to doxology: the song is not merely historical reflection but an act of praise that declares YHWH's incomparability.</p>",
        "5": "<p><strong>šiḥēt lô lōʾ bānāyw mûmām</strong> — 'Corruption is his — not his sons, their defect.' The verse is textually complex; the MT reads 'he acted corruptly toward him — not his sons, their blemish.' The <em>šāḥat</em> (H7843 — to corrupt, ruin, destroy) refers to Israel's corruption of their relationship with YHWH. The contrast with <em>bānāyw</em> (his sons) is ironic: Israel is called YHWH's firstborn son (Exod 4:22) and yet has acted as someone unrelated, with <em>mûm</em> (blemish, defect — H3971, the same word for disqualifying defects in sacrificial animals, Lev 22:19-25). Israel's corruption is all the more scandalous because they were sons — blemished sons who disqualified themselves from the covenant relationship.</p>",
        "6": "<p><strong>hăleyYHWH tiqmĕlû-zōʾt ʿam nāḇāl welōʾ ḥākhām</strong> — 'Is this how you repay YHWH, O foolish and unwise people?' <em>Nāḇāl</em> (H5036 — foolish, senseless, the person who has no moral-spiritual perception) appears in Ps 14:1 ('The fool says in his heart, “There is no God”') and denotes not intellectual deficiency but moral rejection of YHWH. The rhetorical question <em>hăleyYHWH tiqmĕlû-zōʾt</em> (do you repay YHWH with this?) frames Israel's apostasy as an act of gross ingratitude. The word <em>qāmal</em> (H1580 — to repay, deal, do to) is the same word used for YHWH's gracious dealings with Israel (v7's <em>gāmal</em>) — the song uses YHWH's generosity as an indictment of Israel's ingratitude.</p>",
        "7": "<p><strong>zekhōr yĕmôt ʿôlām bînû šĕnôt dōr-wādōr</strong> — 'Remember the days of old; consider the years of many generations.' The appeal to historical memory (<em>zekhōr</em> — H2142, the covenant verb of remembrance) is the foundation of covenantal ethics. <em>Yĕmôt ʿôlām</em> (days of eternity/ancient times) points to pre-Israelite history — the structuring of the nations. <em>Šeʾal ʾāḇîkhā</em> (ask your father) and <em>zeqênêkhā</em> (your elders) identifies the transmission chain: patriarchal tradition is the medium through which YHWH's history of election is preserved. The question to ask: <em>binhāl ʿelyôn gôyim</em> — when the Most High divided the nations (at Babel, Gen 10-11), he did so with Israel in mind.</p>",
        "8": "<p><strong>bĕhanhēl ʿelyôn gôyim bĕhaprîḏô bĕnê ʾādām</strong> — 'When the Most High gave the nations their inheritance, when he divided mankind.' The key term <em>ʿelyôn</em> (H5945 — Most High) is the El-Elyon title used by Melchizedek (Gen 14:18-22) — YHWH as cosmic sovereign over all nations. The phrase <em>yatsseḇ gĕḇulōt ʿammîm lĕmispar bĕnê yisrāʾel</em> (he fixed the borders of the peoples according to the number of the sons of Israel) is theologically dense: the nations' geography was configured in advance to correspond to Israel's tribal count. The LXX reads 'sons of God' (confirmed by a Qumran scroll, 4QDeut-j), suggesting an early tradition that the nations were allotted to angelic overseers while YHWH kept Israel directly for himself.</p>",
        "9": "<p><strong>kî ḥēleq YHWH ʿammô yaʿăḇōḇ ḥebel naḥălāṯô</strong> — 'For YHWH's portion is his people; Jacob his allotted heritage.' <em>Ḥēleq</em> (H2506 — portion, share, allotment) applied to Israel is the theological inverse of Israel's confession that 'YHWH is my portion' (Ps 16:5; 73:26; 119:57). The relationship is mutual: Israel is YHWH's possession; YHWH is Israel's portion. The word <em>ḥeḇel</em> (H2256 — measuring line, allotment) evokes the land-division imagery: as a surveyor's line marks off a property, YHWH has marked out Israel as his own territory among all nations. <em>Yaʿăḇōḇ</em> (Jacob — the personal name for the patriarch and his people) personalizes the election: not an abstract people but the children of the man who wrestled with God.</p>",
        "10": "<p><strong>yimtsāʾēhû bĕʾerets midbār ûḇetōhû yĕlēl yĕšimōn</strong> — 'He found him in a desert land, in a howling wilderness waste.' The wilderness imagery — <em>midbār</em> (desert), <em>tōhû</em> (formless waste — H8414, the same word as in Gen 1:2 for the pre-creation chaos), <em>yĕšimōn</em> (wasteland, desolation — H3452) — describes the Exodus context. YHWH found Israel (<em>mātsa</em> — H4672, the verb of providential discovery used for finding a spouse, Gen 2:20) when they were nothing — no land, no national identity, no resources. The threefold parallelism of desolation words emphasizes that Israel's origins were in a place of absolute helplessness. YHWH's election began precisely where human capacity ended.</p>",
        "11": "<p><strong>kenesher yāʿîr qinnô ʿal-gôzālāyw yĕraḥēp</strong> — 'As an eagle stirs up its nest, hovers over its young.' The eagle metaphor (<em>nesher</em> — H5404, eagle, vulture) portrays YHWH as the parent raptor who trains its young to fly: <em>yāʿîr qinnô</em> (stirs up its nest), <em>yĕraḥēp ʿal-gôzālāyw</em> (broods over its nestlings — the same verb as the Spirit hovering over the waters in Gen 1:2), <em>yipros kĕnāpāyw</em> (spreads its wings), <em>yiqqāḥēhû</em> (takes him up), <em>yiśśāʾēhû ʿal-ʾeḇrāṯô</em> (carries him on its pinions). The Exodus is portrayed as divine flight-training: YHWH forced Israel out of Egypt's comfortable nest to discover they could fly — carried by YHWH's own wings when they faltered.</p>",
        "12": "<p><strong>YHWH bādād yanḥennû weʾên ʿimmô ʾēl nēkhār</strong> — 'YHWH alone led him; no foreign god was with him.' The word <em>bādād</em> (H905 — alone, by himself) is the key word: YHWH's exclusive care for Israel in the wilderness brooked no partnership with other deities. The phrase <em>ʾēl nēkhār</em> (foreign god — H5236) refers to the gods of surrounding nations. The wilderness period was the time of covenant exclusivity — no Baal-shrines, no Asherah poles in the desert. This verse establishes the theological baseline against which Israel's later apostasy (vv15-18) will be measured: YHWH alone had done it all, and Israel repaid that sole Provider with polytheism.</p>",
        "13": "<p><strong>yarkiḇēhû ʿal-bāmôtê ʾārets vayyōʾkhel tĕnûḇōt śādāy</strong> — 'He made him ride on the heights of the land and fed him with the produce of the field.' The entry into Canaan is described in lush agricultural terms: <em>bāmôtê ʾārets</em> (heights of the land — H1116, the commanding positions, the best terrain), <em>tĕnûḇōt śādāy</em> (produce of the field), <em>sûr dĕḇaš</em> (honey from the rock — wild honey), <em>šemen meḥalmîš tsûr</em> (oil from flint rock — olive trees growing in rocky soil). The verse celebrates the paradoxical fertility of Canaan: honey where one would expect only stone, oil from rocks. The land's abundance was YHWH's gift, creating the preconditions for the apostasy that follows (v15: Jeshurun grew fat).</p>",
        "14": "<p><strong>ḥemʾat bāqār weḥăleḇ tsōʾn ʿim-ḥēleḇ kārîm</strong> — 'Curds from the herd, milk from the flock, with fat of lambs.' The food gifts continue: <em>ḥemʾat bāqār</em> (curds of cattle), <em>ḥăleḇ tsōʾn</em> (milk of sheep), <em>ḥēleḇ kārîm</em> (fat of rams — H3733, the choicest rams), <em>ʾêlîm</em> (rams), <em>ʿăttûdîm</em> (male goats), <em>kelĕyôt ḥittāh</em> (finest wheat — literally kidneys of wheat, the central grain), <em>dam ʿēnāḇ</em> (blood of the grape, i.e., wine). The abundance is expressed through seven food categories — a complete provision. The gifts of Canaan were not Israel's achievement but YHWH's provision, making the coming apostasy an act of ingratitude against a generous benefactor.</p>",
        "15": "<p><strong>vayyišman yĕšûrûn vayyibʿāṭ šāmantā ʿābîṯā kāśîṯā</strong> — 'Jeshurun grew fat and kicked — you became fat, thick, gorged.' <em>Yĕšûrûn</em> (H3484 — the upright one, the noble one) is a poetic name for Israel emphasizing their calling to uprightness; its use in a context of rebellion is ironic. The word <em>šāman</em> (H8080 — to grow fat) leads to <em>bāʿaṭ</em> (H1163 — to kick like an animal). Three verbs accumulate: <em>šāmantā</em> (you became fat), <em>ʿābîṯā</em> (you became thick/heavy), <em>kāśîṯā</em> (you became covered/coated with fat — from H3780). Prosperity was the mechanism of apostasy: fullness led to forgetfulness. The specific betrayal: <em>vayyiṭṭōš ʾĕlôah ʿāśāhû</em> (he abandoned the God who made him) and <em>vayyenabbēl tsûr yĕšûʿāṯô</em> (treated the Rock of his salvation with contempt).</p>",
        "16": "<p><strong>yaqnîʾûhû bezārîm betôʿăḇōt yakhʿîsûhû</strong> — 'They made him jealous with strange gods, provoked him with abominations.' The verb <em>qānāʾ</em> (H7065 — to be jealous, provoke to jealousy) is YHWH's covenant passion: He described Himself as a <em>ʾēl qannāʾ</em> (jealous God) in the Decalogue (Exod 20:5). The word <em>zārîm</em> (H2114 — strange, alien, foreign) designates the gods as fundamentally other — not merely inferior but alien to the covenant relationship. <em>Tôʿăḇōt</em> (abominations — H8441) is the Deuteronomic term for Canaanite religious practices (Deut 7:25-26; 12:31; 18:9-12). The song traces apostasy from a specific sequence: prosperity → abandonment → jealousy-provoking with foreign worship.</p>",
        "17": "<p><strong>yizbeḥû laššēdîm lōʾ ʾĕlōah</strong> — 'They sacrificed to demons, not God.' <em>Šēdîm</em> (H7700 — demons, malevolent supernatural beings) is used only here and in Ps 106:37 in the Hebrew Bible; Akkadian <em>šēdu</em> was a protective spirit, but its use in the context of Canaanite child sacrifice and foreign worship transforms it into a term for demonic forces. Paul quotes this verse in 1 Cor 10:20 when warning against eating food sacrificed to idols: 'what pagans sacrifice, they sacrifice to demons.' The appositive <em>lōʾ ʾĕlōah</em> (not God) denies any genuine divine reality to the objects of worship — they are <em>ḥădāšîm miqqārōḇ bāʾû</em> (newcomers that came lately), without historical pedigree, and <em>lōʾ śĕʿārûm ʾăḇōtêhem</em> (your ancestors did not dread them).</p>",
        "18": "<p><strong>tsûr yĕlādĕkhā tĕšî vattiškāḥ ʾēl mĕḥōlĕlekhā</strong> — 'You were unmindful of the Rock who fathered you, and forgot the God who gave you birth.' The parental metaphors for YHWH reach their fullest expression here: <em>yĕlādĕkhā</em> (who fathered/bore you — from <em>yālad</em>, to give birth; the root encompasses both male and female generative acts). The verb <em>tĕšî</em> (H7876 — to be unmindful, forget by neglect) paired with <em>šākaḥ</em> (H7911 — to forget) describes the spiritual amnesia of Israel. YHWH as Rock (<em>tsûr</em>) of begetting connects to the creation motif of v18: Israel forgot its own origin. The Song will now describe YHWH's response to this forgetting.</p>",
        "19": "<p><strong>vayyarʾ YHWH vayyinʾāts mikaʿas bānāyw ûḇĕnōṯāyw</strong> — 'YHWH saw it and rejected, provoked by his sons and daughters.' The divine response to apostasy: <em>rāʾāh</em> (he saw — covenant witness) and <em>nāʾats</em> (H5006 — to spurn, reject, treat with contempt). The rejection of Israel (<em>bānāyw ûḇĕnōṯāyw</em> — his sons and daughters) is a direct reversal of the election language: YHWH who called them sons now rejects them as sons. The cause: <em>mikaʿas</em> (from the provocation/anger they caused — H3708, the noun form of the verb <em>kaʿas</em>, to vex, provoke). The song moves from Israel's apostasy to YHWH's judicial response, setting up the complex of blessings and curses that will unfold in history.</p>",
        "20": "<p><strong>vayyōʾmer ʾastîrāh fānay mēhem</strong> — 'He said: I will hide my face from them.' <em>Hastārāt pānîm</em> (hiding of the face) is the technical term for the withdrawal of YHWH's covenantal presence and protective favor (cf. Ps 30:7; Isa 8:17; 54:8; 59:2). When YHWH hid his face, Israel was exposed to its enemies without divine protection. The diagnosis: <em>kî dôr tahpukhōt hēmmāh bānîm lōʾ-ʾēmun bām</em> — 'for they are a perverse generation, sons in whom there is no faithfulness.' <em>Tahpukhōt</em> (H8419 — perversities, inversions) describes a people who invert all moral and theological standards. <em>ʾĒmun</em> (H529 — faithfulness, reliability) is the root of <em>ʾĕmûnāh</em>: the sons lacked the covenant integrity that YHWH had shown them (v4).</p>",
        "21": "<p><strong>hēm qinʾûnî belōʾ-ʾēl kiʿăsûnî behablêhem</strong> — 'They made me jealous with what is no god, provoked me with their vanities.' The divine response to Israel's jealousy-provoking apostasy was itself a form of jealousy-provocation in reverse: <em>vaʾănî ʾaqnîʾēm belōʾ-ʿam beḡôy nāḇāl ʾakhʿîsēm</em> — 'I will make them jealous with what is no people; I will provoke them with a foolish nation.' YHWH's response was not direct punishment but the use of a <em>lōʾ-ʿam</em> (no-people — H5971) — an entity that did not count as a proper nation — to provoke Israel's jealousy. Paul quotes this in Rom 10:19 as the prophetic warrant for the Gentile mission: the Gentiles' inclusion provokes Israel to jealousy (Rom 11:11,14).</p>",
        "22": "<p><strong>kî-ʾēš qādĕḥāh bĕʾappî vattiqqad ʿad-šĕʾôl taḥtît</strong> — 'For a fire is kindled in my anger, and it burns to the depths of Sheol.' The metaphor of YHWH's <em>ʾap</em> (H639 — anger, nose/nostrils, from the flared nostrils of rage) as a cosmic fire (<em>ʾēš</em> — H784) that consumes from the earth's foundations (<em>ûtĕhōm ʾereṣ</em>) to the heights (<em>vayyōkhēl ʾereṣ ûḇûlāh</em>) describes the totality of covenant judgment. The fire reaches <em>šĕʾôl taḥtît</em> (the lowest Sheol) — the cosmological extreme — and <em>taḥtît</em> (lowest place, H8482) signals that YHWH's judgment pierces even the realm of the dead. The covenant curses of Deut 28 are not metaphors but actual historical catastrophes that would consume the land.</p>",
        "23": "<p><strong>ʾaspeh ʿălêhem rāʿôt ḥitstay ʾăkhalleh-bām</strong> — 'I will heap calamities upon them; I will spend my arrows against them.' The accumulation of covenant curse weapons: <em>rāʿôt</em> (calamities, evils — H7451), <em>ḥētsîm</em> (arrows — H2671, the missiles of divine judgment). The phrase <em>ḥitstay ʾăkhalleh-bām</em> (I will exhaust my arrows against them) uses the idiom of a warrior emptying his quiver into an enemy. But the verse anticipates a limit: YHWH will exhaust the arrows before exhausting Israel — judgment has an end. This anticipates the turn in v36 where YHWH will vindicate his people. The enemies' gloating (<em>lûlê kāʿas ʾōyēḇ</em> — v27) is what stays YHWH's final judgment.</p>",
        "24": "<p><strong>mĕzê rāʿāḇ ûlĕḥumê rešep ûqēṭeḇ mĕrîrî</strong> — 'Wasting from famine, consumed by plague and bitter pestilence.' The covenant curse catalog continues: <em>mĕzê rāʿāḇ</em> (waste/weakening from famine — H4198 from H4198), <em>lĕḥumê rešep</em> (devoured by <em>rešep</em> — H7565, the Canaanite plague-deity, here used for epidemic disease), <em>qēṭeḇ mĕrîrî</em> (bitter pestilence — H6986, a word for a specific severe disease). The personalizing of plague forces as divine weapons echoes Hab 3:5 where plague and pestilence march before YHWH in the divine warrior theophany. These are not natural disasters but covenantal judicial punishments directed against Israel's apostasy.</p>",
        "25": "<p><strong>miḥûts tĕšakkĕl-ḥāreḇ ûmeḥăḏārîm ʾêmāh</strong> — 'Outside the sword bereaves; inside, terror.' The war-imagery: <em>ḥāreḇ</em> (the sword — H2719) kills outside; <em>ʾêmāh</em> (terror — H367) fills the inner rooms. The comprehensive scope — young man (<em>baḥûr</em>), virgin (<em>bĕṯûlāh</em>), nursing infant (<em>yônēq</em>), grey-haired elder (<em>ʾîš śêḇāh</em>) — means no demographic was exempt from covenant judgment. This catalog of the vulnerable matches the descriptions of siege and conquest throughout Lamentations and Jeremiah 6-8. The judgment that Moses predicted became the lived experience of Jerusalem's fall in 586 BCE.</p>",
        "26": "<p><strong>ʾāmartî ʾapʾêhem</strong> — 'I said I would scatter them to the corners.' <em>pāʾāh</em> (H6284 — to scatter, blow away) with <em>appêhem</em> (I would scatter them to corners/extremities — H6284, rare verb) describes the diaspora threat. The phrase <em>ʾašbîṯāh meʾĕnôš zikrām</em> (I would make the memory of them cease among humanity) is the most extreme possible threat — total national obliteration, the erasure of Israel from history. But this ultimate judgment is withheld (v27) for a reason that is not Israel's goodness but YHWH's concern for His own name and reputation among the nations. The preservation of Israel became inseparable from YHWH's honor among the Gentiles.</p>",
        "27": "<p><strong>lûlê kaʿas ʾōyēḇ ʾāgûr</strong> — 'Were it not that I feared provocation by the enemy.' The divine reasoning: YHWH withheld total destruction of Israel because the enemies would misattribute it. <em>pĕn-yĕnakkĕrû tsārêhem pĕn-yōʾmĕrû yādênû rāmāh</em> (lest their enemies misunderstand, lest they say 'our hand is triumphant'). The enemies' pride would eclipse YHWH's own glory: they would attribute Israel's destruction to their own power rather than recognizing it as YHWH's judgment. This is not mercy toward Israel but jealousy for YHWH's own glory — a theological theme developed extensively in Ezekiel (Ezek 20:9,14,22; 36:22-23). Israel's preservation served YHWH's self-revelation to the nations.</p>",
        "28": "<p><strong>kî-gôy ʾōḇad ʿētsôt hēmmāh weʾên bāhem tĕḇûnāh</strong> — 'For they are a nation void of counsel, and there is no understanding in them.' The diagnosis of Israel's spiritual condition during apostasy: <em>ʾāḇad ʿētsôt</em> (losing counsel/advice — H6098 from H3289, to counsel) and <em>tĕḇûnāh</em> (understanding — H8394). The loss of wisdom is the theological consequence of covenant abandonment: YHWH's Torah was the source of Israel's <em>ḥokhmāh</em> (wisdom, Deut 4:6), so abandoning Torah meant abandoning wisdom. A nation without wisdom makes self-destructive decisions — precisely what v29's conditional lament describes.</p>",
        "29": "<p><strong>lû ḥākhĕmû yaśkîlû zōʾt yāḇînû lĕʾaḥărîtām</strong> — 'If they were wise they would understand this; they would discern their end.' The conditional <em>lû</em> (would that, if only) frames the lament: the wisdom Israel lacked would have enabled them to read their own future from the covenant structure. <em>ʾAḥărîtām</em> (their end — H319, the final outcome) is what wisdom reveals: covenantal cause and effect is intelligible to those who think clearly. The rhetorical question that follows (v30: how could one chase a thousand?) implies that Israel's military defeats were intelligible signs of YHWH's departure — but only to those with the wisdom to interpret them correctly.</p>",
        "30": "<p><strong>êkhāh yirdōp ʾeḥād ʾelep ûšnayim yānîsû rĕḇāḇāh</strong> — 'How could one chase a thousand, and two put ten thousand to flight?' The mathematical impossibility (<em>ʾeḥād ʾelep</em> = one chases 1,000; <em>šnayim rĕḇāḇāh</em> = two put 10,000 to flight) inverts the covenant blessing of Deut 28:7 (where Israel would pursue enemies in seven directions). Military reversal was the clearest sign that YHWH had sold them (<em>mākār</em> — H4376, sold/delivered into enemy hands — the same verb used for Israelites sold into slavery) and YHWH had abandoned them. The enemies' victory was not their own power but YHWH's judicial use of them as instruments.</p>",
        "31": "<p><strong>kî lōʾ kĕtsûrênû tsûrām weʾōyĕḇênû pĕlîlîm</strong> — 'For their rock is not like our Rock; even our enemies themselves concede this.' <em>Tsûr</em> (Rock — H6697) is one of the Song's central divine titles, appearing in vv4,15,18,30,31,37. The Rock comparison is the pivot: even Israel's enemies could theoretically judge that YHWH is incomparable — their own gods being demonstrably inferior. The phrase <em>weʾōyĕḇênû pĕlîlîm</em> (our enemies are judges — H6414 from H6419, to judge, arbitrate) suggests that even a neutral court of Israel's enemies would have to concede YHWH's superiority. The incomparability of YHWH is a point that cannot be disputed even by hostile witnesses.</p>",
        "32": "<p><strong>kî miggefen sĕdōm gapnām ûmiššadĕmōt ʿămōrāh</strong> — 'For their vine is from the vine of Sodom and from the fields of Gomorrah.' The enemies' vine is corrupt: <em>ʿănāḇêmô ʿănāḇê rōʾš</em> (their grapes are grapes of gall) and <em>ʾaškelōt mĕrōrōt lāmô</em> (their clusters are bitter). Sodom and Gomorrah (H5467, H6017) are the paradigmatic corrupt cities destroyed by YHWH for wickedness (Gen 19). To describe the enemy nations' identity in terms of Sodom's vine is to characterize them as worthy of YHWH's judgment — their temporary use as instruments of judgment against Israel does not make them righteous. The nations are not YHWH's servants but His tools, themselves liable to judgment.</p>",
        "33": "<p><strong>ḥămaṯ tannînîm yênām weʾrōš pĕtānîm ʾakhzār</strong> — 'Their wine is the poison of serpents, the cruel venom of asps.' The metaphors of venom and poison continue: <em>ḥămaṯ tannînîm</em> (venom/poison of <em>tannîn</em> — H8577, the great sea dragon/serpent, the chaos monster) with <em>ʾrōš pĕtānîm ʾakhzār</em> (cruel head-poison of vipers). The word <em>ʾakhzār</em> (H394 — cruel, fierce) applied to viper venom describes the irreversible, lethal effect. The nations that Israel served in apostasy — those who enticed Israel to idolatry — were themselves drinking poison. The imagery anticipates the nations' ultimate destruction described in vv40-43.</p>",
        "34": "<p><strong>hălōʾ-hûʾ kāmûs ʿimmādî ḥāṯûm bĕʾôtsĕrōṯāy</strong> — 'Is this not stored up with me, sealed in my treasuries?' YHWH's judgment is not improvised but stored (<em>kāmas</em> — H3647, to lay up in store) and sealed (<em>ḥātam</em> — H2856, to seal, stamp with a signet). The treasuries (<em>ʾôtsĕrôt</em> — H214, storehouses) of divine judgment recall the storehouses of Deut 28:12 (the storehouses of rain and blessing) now repurposed as repositories of curse. The divine patience — judgment stored and sealed — means YHWH's punishments are fully prepared but await the appointed time. Both the apostasy and the judgment were known to YHWH before Israel entered the land.</p>",
        "36": "<p><strong>kî-yādîn YHWH ʿammô weʿal-ʿăḇādāyw yitnēḥām</strong> — 'For YHWH will vindicate his people and have compassion on his servants.' The turn of the Song: after the catalog of judgment, the divine <em>nîḥam</em> (H5162 — to relent, be moved to compassion, have pity) pivots from doom to mercy. <em>Yādîn</em> (he will judge/vindicate — H1777 from H1779 dîn, to judge) has a double meaning: to judge Israel's enemies and to vindicate Israel itself. The condition: <em>kî yirʾeh kî-ʾāzĕlat yād</em> (when he sees that their strength is gone — H230) and <em>weʾepes ʿātsûr weʿāzûb</em> (and there is none remaining, restrained or free). YHWH's compassion is triggered by Israel's utter helplessness — a theme that runs through the prophets (Isa 40:27-31; Hos 2:14-15).</p>",
        "37": "<p><strong>weʾāmar ʾê ʾĕlōhêmô tsûr ḥāsāyû ḇô</strong> — 'He will say: Where are their gods, the rock in which they took refuge?' The ironic question — directed at Israel after its collapse — exposes the futility of idol worship. <em>Tsûr ḥāsāyû</em> (the rock they took refuge in) is the anti-YHWH: the false security of Canaanite deities. The questions accumulate: <em>ʾăšer ḥēleḇ zĕḇāḥêmô yōkhēlû yišṯû yên nĕsîkhēhemô</em> (who ate the fat of their sacrifices and drank the wine of their libations). The gods who received the sacrifices and libations have abandoned their worshipers in the hour of crisis. The Song forces the recognition: YHWH alone is the Rock — and the judgment that came on Israel was from that same Rock, not from the worthless gods they chased.</p>",
        "38": "<p><strong>yāqûmû weyzaʿrûkem yihî ʿălêkhem sēter</strong> — 'Let them rise up and help you; let them be your protection!' The sarcastic divine challenge — YHWH daring the false gods to protect Israel in the moment of crisis — proves their powerlessness. The verb <em>sēter</em> (H5643 — hiding place, shelter, protection) is the same word used for YHWH's protection in Ps 27:5; 31:20; 91:1. The false gods offered no <em>sēter</em>; only YHWH was the true hiding place. This verse functions as a rhetorical pivot: the gods that received sacrifice and libation are nowhere in Israel's crisis — their absence proves YHWH's exclusive sovereignty.</p>",
        "39": "<p><strong>rĕʾû ʿattāh kî ʾănî ʾănî hûʾ weʾên ʾĕlōhîm ʿimmādî</strong> — 'See now that I, even I, am he, and there is no god besides me.' The divine self-declaration is the theological center of the entire Song: <em>ʾănî ʾănî hûʾ</em> (I, I am he — the formula repeated in Isa 41:4; 43:10,13; 46:4; 48:12) asserts YHWH's absolute uniqueness. The fourfold divine claim: <em>ʾĂnî ʾămît veʾăḥayyeh</em> (I kill and I make alive), <em>māḥatsî vaʾănî ʾerpāʾ</em> (I wound and I heal). The sovereign control over death and life — mortality and resurrection — belongs to YHWH alone. <em>weʾên miYYādî matstsîl</em> (no one can deliver from my hand) closes the claim with absolute power. This verse is the monotheistic summit of Deuteronomy.</p>",
        "40": "<p><strong>kî-ʾessāʾ el-šāmayim yādî</strong> — 'For I lift my hand to heaven.' The divine oath formula: lifting the hand to heaven (<em>nāśāʾ yād lešāmayim</em>) is the ultimate oath gesture, witnessed by the cosmic heavens (cf. Gen 14:22; Dan 12:7; Rev 10:5-6 where the angel swears by the Eternal). YHWH swears by his own eternal life (<em>ḥay-ʾănî leʿōlām</em> — as I live forever): the oath is unbreakable because YHWH's own existence is the guarantee. The content of the oath: the coming judgment on YHWH's enemies and the vindication of His people. The judicial self-oath makes the coming actions inescapable and irreversible.</p>",
        "41": "<p><strong>ʾim-šanôtî beruq ḥarbi wetōʾḥez bammišpāṭ yādî</strong> — 'When I sharpen my flashing sword and my hand takes hold on judgment.' The divine warrior imagery: <em>bareq ḥarbî</em> (flashing/lightning sword — H1300 bārāq, lightning, H2719 ḥereb) and <em>mišpāṭ yādî</em> (my hand's judgment). YHWH will <em>šūb nāqām leṣārāyw</em> (return vengeance to his adversaries) and <em>yešallēm lĕśōnĕʾāyw</em> (repay those who hate him). The word <em>nāqām</em> (H5359 — vengeance, retribution) is not personal vindictiveness but the covenantal execution of justice: YHWH as the kinsman-redeemer (<em>gōʾēl</em>) avenging the blood of his servants.</p>",
        "42": "<p><strong>ʾaškkîr ḥitstay middām ûḥarbî tōkhēl bāśār</strong> — 'I will make my arrows drunk with blood; my sword shall devour flesh.' The conquest imagery: <em>ḥitstay middām</em> (arrows drunk with blood) and <em>ḥarbî tōkhēl bāśār</em> (sword eating flesh). The target: <em>middam ḥālāl weššiḇyāh mērōʾš parʿôt ʾōyēḇ</em> (from the blood of the slain and captives, from the long-haired heads of the enemy). <em>Parʿôt</em> (H6546 — the unkempt long hair of warriors, loose hair) identifies the enemies as wild-haired warriors (perhaps referring to the Canaanites' untrimmed hair as a sign of their non-Israelite status). The divine warrior will complete what Israel's conquest began.</p>",
        "43": "<p><strong>harnînû gôyim ʿammô kî dam-ʿăḇādāyw yiqqôm</strong> — 'Rejoice, O nations, with his people, for he avenges the blood of his servants.' The climactic call to the nations to join in Israel's praise is remarkable: <em>harnînû gôyim ʿammô</em> (shout for joy, O nations, his people — the nations and Israel praised together). Paul quotes this verse in Rom 15:10 as the prophetic basis for Gentile inclusion in Israel's praise: 'Rejoice, O Gentiles, with his people.' The eschatological vision is one of nations joining Israel's praise — the same universalism anticipated in Isa 2:2-4; 60:1-3. The Song ends not with national exclusivism but with cosmic doxology: YHWH vindicates the blood of his servants and makes atonement for his land and people.</p>",
        "44": "<p><strong>vayyāḇōʾ mōšeh vaydabbēr ʾet-kol-diḇrê haššîrāh-hazzōʾt</strong> — 'Moses came and spoke all the words of this song.' The narrative frame resumes: Moses and Joshua (<em>yĕhôšuaʿ</em> — here called <em>hôšēaʿ</em>, his original name before Moses renamed him) recited the song to the assembled Israel. The mention of Joshua's presence at the song's delivery foreshadows the imminent transfer of leadership — the Song's message of covenant consequences would be the theological framework within which Joshua would lead the conquest. The song was not merely poetry but a prophetic document programing Israel's covenant future.</p>",
        "45": "<p><strong>vaykkal mōšeh lĕdabbēr ʾet-kol-haddĕḇārîm hāʾēlleh</strong> — 'When Moses finished speaking all these words to all Israel.' The completion formula (<em>vaykkal</em> — H3615, to finish, complete) signals the end of Moses's final literary-prophetic composition. The phrase <em>ʾel kol-yisrāʾel</em> (to all Israel) is inclusive — the entire community was the audience and recipient. The Song's message was not for an elite but for the common people who would live through covenant blessings and curses. The pedagogical strategy (teaching the song so it would be memorized, Deut 31:19) ensured that the theological framework would persist even when Israel forgot the words of the Torah itself.</p>",
        "46": "<p><strong>vayyōʾmer ʾălêhem śîmû lĕḇaḇĕkhem lĕkhol-haddĕḇārîm</strong> — 'He said to them: Set your heart on all the words.' The final instruction: <em>śîm lēḇāḇ</em> (to set the heart on — H3824 + H7760) means to internalize, not merely memorize. The purpose: <em>tĕtsawwûm ʾet-bĕnêkhem lišmōr laʿăśôt ʾet-kol-diḇrê hattôrāh hazzōʾt</em> (to command your children to keep and do all the words of this Torah). The transmission chain — parent to child — was the mechanism of covenant continuity. The reason: <em>kî lōʾ-dāḇār rēq hûʾ mikkkem</em> (for this is not an empty word for you). Moses denied that Torah was abstract or irrelevant — it was <em>ḥayyêkhem</em> (your life) and would extend your days in the land.</p>",
        "47": "<p><strong>kî lōʾ-dāḇār rēq hûʾ mikkkem kî-hûʾ ḥayyêkhem</strong> — 'For this is not an empty word for you; it is your very life.' <em>Dāḇār rēq</em> (empty/idle word — H7387 rêq, empty, vain, H1697 dāḇār) is the accusation that Torah is merely ceremonial or irrelevant. Moses's rebuttal: <em>hûʾ ḥayyêkhem</em> (it is your life). The word <em>ḥayyîm</em> (H2416 — life, both biological and covenant life) is the ultimate summation of Torah's purpose. Deut 30:19 gave Israel the choice of life or death; now Moses specifies that the word itself IS the life. This verse anticipates Jesus's claim that 'man shall not live by bread alone but by every word from the mouth of God' (Matt 4:4, quoting Deut 8:3) and John's identification of the Word with life (John 1:4; 6:63).</p>",
        "48": "<p><strong>vaydabbēr YHWH ʾel-mōšeh beʿetsem hayyôm hazzeh lēʾmōr</strong> — 'YHWH spoke to Moses on that very day, saying.' The phrase <em>beʿetsem hayyôm hazzeh</em> (on this very day — H6675) indicates immediacy — the divine command came precisely when Moses had finished addressing Israel. The day of final address was also the day of Moses's death summons. YHWH directed Moses to <em>hahar hāʾăḇārîm hazzeh har-nĕḇô</em> (this mountain of the Abarim, Mount Nebo) — the specific peak from which Moses would see the land and then die.</p>",
        "49": "<p><strong>ʿălēh ʾel-har hāʾăḇārîm hazzeh har-nĕḇô</strong> — 'Go up to this mountain of the Abarim, Mount Nebo.' <em>Har hāʾăḇārîm</em> (Mountain of the Abarim — H5682, the heights across the Jordan from Jericho) is the trans-Jordanian plateau. <em>Har-nĕḇô</em> (Mount Nebo — H5015) was the specific peak, identified today with Jebel en-Neba (~810m elevation), from which the promised land was visible in panoramic view. <em>Urêh ʾet-ʾerets kĕnaʿan</em> (see the land of Canaan) — Moses would see what he could not enter. The reason recalled: the Waters of Meribah-Kadesh incident (Num 20:1-13), where Moses struck the rock instead of speaking to it, failing to demonstrate YHWH's holiness to Israel.</p>",
        "50": "<p><strong>ûmût behāhār ʾăšer ʾattāh ʿōleh šāmmāh</strong> — 'Die on the mountain which you are going up.' The command to die (<em>mût</em> — H4191) is not a threat but a divine appointment. <em>Wehēʾāsep ʾel-ʿammêkhā</em> (be gathered to your people) is the honorable death formula for the covenant faithful (cf. Gen 25:8 Abraham; Gen 49:33 Jacob). Moses would die <em>kaʾăšer-mēt ʾaharōn ʾāḥîkhā bĕhar-hōr</em> (as Aaron died on Mount Hor — Num 20:28) — the precedent of the priest dying at his post on the mountain, handing off the office to his successor. Both brothers died in elevated places outside the promised land, their deaths marking the end of the wilderness generation's leadership.</p>",
        "51": "<p><strong>ʿal ʾăšer mĕʿaltem bî bĕtôkh bĕnê yisrāʾel</strong> — 'Because you broke faith with me among the sons of Israel.' The word <em>māʿal</em> (H4603 — breach of faith, covenant treachery, the same word for priests embezzling sacred things) applied to Moses is severe. Moses's sin at Meribah was not simply anger but <em>māʿal</em> — a covenant violation that was communicable, leading Israel to fail to trust YHWH's holiness. The connection between Moses's failure and Israel's subsequent failures suggests that leadership sin had communal consequences. Moses died not for his own sake alone but as the bearer of Israel's corporate failure at Meribah.</p>",
        "52": "<p><strong>kî minneged tirʾeh ʾet-hāʾārets weʾl-šāmmāh lōʾ tāḇôʾ</strong> — 'For you shall see the land only from a distance; you shall not enter it.' The vision without entry — <em>minneged tirʾeh</em> (you will see from opposite/afar — H5048 minneghed) but <em>lōʾ tāḇôʾ šāmmāh</em> (you will not enter there) — was the final gracious gift within the judgment: Moses would see the fulfillment of the promise even as the punishment stood. The divine refusal was not cruelty but consistency: the God who judged Israel for failing to trust His holiness could not exempt His own servant from the same covenant standard. The land <em>ʾăšer-ʾănî nōtēn liḇnê yisrāʾel</em> (which I am giving to the sons of Israel) — the promise was kept, just not through Moses.</p>",
    },
    "33": {
        "1": "<p><strong>wĕzōʾt habbĕrākhāh ʾăšer bērakh mōšeh ʾîš hāʾĕlōhîm</strong> — 'This is the blessing with which Moses the man of God blessed the sons of Israel.' The superscription frames the passage as the final act of Moses's prophetic-priestly role: <em>ʾîš hāʾĕlōhîm</em> (man of God — H376, H430 — a prophetic title for one who has direct access to YHWH, used of Elijah, Elisha, Samuel) is the highest honorific in Israel's prophetic tradition. The blessing (<em>bĕrākhāh</em> — H1293) was the patriarchal prerogative Moses carried as Israel's leader. Like Jacob's blessing of the twelve sons (Gen 49), Moses's blessing reviewed each tribe's character and destiny — but from the perspective of YHWH's election rather than merely genealogical traits.</p>",
        "2": "<p><strong>YHWH missînay bāʾ wĕzāraḥ miśśēʿîr lāmô</strong> — 'YHWH came from Sinai and dawned from Seir upon them.' The theophanic hymn that opens Moses's blessing is one of the oldest Hebrew poems: YHWH as the divine warrior marching to Israel's aid from Sinai (<em>sînay</em>), Seir (<em>śēʿîr</em>), and Mount Paran (<em>har pārān</em>). The three directional references correspond to the Sinai peninsula region. The word <em>zāraḥ</em> (H2224 — to rise, shine like the sun) applies the solar imagery of divine theophany. <em>ʾātāh mirĕḇĕḇōt qōdeš</em> (he came from the holy myriads — from Sinai's ten-thousands of holy ones) identifies the angelic/covenant retinue accompanying YHWH. The parallel in Judg 5:4-5 (Deborah's Song) and Hab 3:3-4 shows this was a standard Israelite theophanic tradition.</p>",
        "3": "<p><strong>ʾaf ḥōḇēḇ ʿammîm kol-qĕdōšāyw bĕyādekā</strong> — 'Indeed, he loves his peoples; all his holy ones are in your hand.' <em>Ḥōḇēḇ</em> (H2245 — to cherish, love warmly) — a rare verb found only here — describes YHWH's affectionate love for Israel. The phrase <em>kol-qĕdōšāyw bĕyādekā</em> (all his holy ones are in your hand) places all who belong to YHWH under His sovereign protection. The subsequent phrase <em>hēm tukku lĕraglikhā yiśśā middabbĕrōtêkhā</em> — 'they bowed down at your feet, accepted your words' — describes Israel's covenant submission at Sinai: the people who received Torah bowed before YHWH as covenant suzerain.</p>",
        "4": "<p><strong>tôrāh tsiwwāh-lānû mōšeh mōrāšāh qĕhillat yaʿăqōḇ</strong> — 'Moses commanded us the Torah, a possession/heritage of the congregation of Jacob.' The verse is a liturgical formula recited in Israel — <em>mōrāšāh</em> (H4181 — possession, inheritance, heritage; from H3423 yāraš, to inherit/possess) frames Torah not as an external imposition but as Israel's family inheritance. <em>Qĕhillat yaʿăqōḇ</em> (the congregation/assembly of Jacob — H6951) identifies the community as the covenantal gathering of Jacob's descendants. The Torah was the family document of YHWH's household — as much a possession as the land itself.</p>",
        "5": "<p><strong>vayhî ḇîšurûn melek</strong> — 'He became king in Jeshurun.' The kingship of YHWH over Israel (<em>melek</em> — H4428) was established at the covenant assembly at Sinai: <em>bĕhitʾassep rāʾšê ʿām yaḥad šiḇṭê yisrāʾel</em> (when the heads of the people assembled, the tribes of Israel together). The Sinai theophany was Israel's coronation of YHWH as king — the covenant ratification was a formal acknowledgment of YHWH's sovereignty. This verse anticipates the later debates about human kingship (1 Sam 8:7: 'they have not rejected you, but they have rejected me from being king over them') — YHWH was always king; human kings were his vice-regents.</p>",
        "6": "<p><strong>yĕhî rĕʾûḇēn weʾal-yāmōt ûyĕhî mĕṯāyw mispar</strong> — 'Let Reuben live and not die, though his men be few.' The brevity of Reuben's blessing reflects the tribe's historical trajectory: forfeiting the firstborn's double portion after the sin with Bilhah (Gen 35:22; 49:4), and the tribe's later instability and modest size. <em>Yĕhî rĕʾûḇēn</em> (let Reuben live) is a petition, not a declaration — Moses prayed for a tribe that was in danger of disappearing. The phrase <em>ûyĕhî mĕṯāyw mispar</em> (his men few in number) is either a description of their current state or a qualification of the blessing: even with few men, let them live.</p>",
        "7": "<p><strong>wĕzōʾt lîhûdāh vayyōʾmar</strong> — 'And this for Judah; he said.' Judah's blessing is a military prayer: <em>šĕmaʿ YHWH qôl yĕhûdāh</em> (hear, YHWH, the voice of Judah) and <em>weʾel-ʿammô tĕḇîʾennû</em> (bring him to his people). The hands of Judah contend (<em>yādāyw rāḇ-lô</em>) and YHWH is asked to be his helper against enemies (<em>weʿēzer missārāyw tihyeh</em>). The blessing anticipates Judah's military leadership in Israel's history (Judg 1:1-2 — Judah goes first) and the Davidic dynasty that would emerge from the tribe. The prayer for Judah to return to his people may reflect a historical circumstance of isolation in battle.</p>",
        "8": "<p><strong>ûlĕlēwî ʾāmar tummêkhā weʾûrîkhā lĕʾîš ḥăsîdêkhā</strong> — 'Of Levi he said: Your Thummim and Urim belong to your godly one.' The Levitical blessing centers on the priestly instruments: <em>tummêkhā weʾûrîkhā</em> (your Thummim and Urim — H8550, H224, the lots for divine oracle in the high priest's breastplate). <em>Ḥăsîdêkhā</em> (your godly/faithful one — H2623 from H2617 ḥesed) refers to Levi as YHWH's covenant-loyal servant. The historical basis: Massah (<em>nissîtô bemassāh</em>) and Meribah (<em>tĕrîḇēhû ʿal-mê mĕrîḇāh</em>) — where Levi (cf. Exod 32:26-29 — the golden calf incident) proved covenant loyalty by standing with YHWH against idolaters, even family members.</p>",
        "9": "<p><strong>hāʾōmēr lĕʾāḇîw ûlĕʾimmô lōʾ rĕʾîtîw</strong> — 'Who said of his father and mother, “I do not see them.”' The Levitical commitment to YHWH surpassed family ties: <em>lōʾ rĕʾîtîw</em> (I do not see him), <em>weʾet-ʾeḥāyw lōʾ hikhîr</em> (did not acknowledge his brothers), <em>weʾet-bānāyw lōʾ yādāʿ</em> (did not know his children). This absolute loyalty — the same radical commitment Jesus demanded for discipleship (Matt 10:37; Luke 14:26) — was demonstrated at the golden calf incident when the Levites 'consecrated themselves to YHWH that day at the cost of sons and brothers' (Exod 32:29). The Levitical priestly vocation required the displacement of all other loyalties by covenant loyalty to YHWH.</p>",
        "10": "<p><strong>yôrû mishpāṭêkhā lĕyaʿăqōḇ wetôrāthkhā lĕyisrāʾel</strong> — 'They will teach your ordinances to Jacob and your Torah to Israel.' The Levitical three-fold ministry: teaching (<em>yōrû</em> — H3384, to teach, direct; the root of <em>tôrāh</em>), offering incense (<em>yāśîmû qĕṭôrāh bĕʾappêkhā</em>), and burnt offerings (<em>wekhālîl ʿal-mizbeḥekhā</em>). The teaching ministry of the Levites was the mechanism of covenant transmission — they were the living library of Israel's law (2 Chr 17:7-9; Neh 8:7-9; Mal 2:6-7). The prophetic complaint against priests who failed to teach the Torah (Hos 4:6; Mal 2:8) shows how crucial this function was to Israel's covenant continuity.</p>",
        "11": "<p><strong>bārēkh YHWH ḥêlô ûfoʿal yādāyw tirtsāh</strong> — 'Bless YHWH his wealth and accept the work of his hands.' The prayer for Levitical blessing encompasses both resources (<em>ḥayil</em> — wealth, capacity, substance) and labor (<em>poʿal yādāyw</em> — the work of his hands, the priestly service). The imprecation against enemies: <em>mehātsats mĕqāmāyw ûmeśōnĕʾāyw min-yĕqûmûn</em> (shatter the loins of his attackers and those who hate him, so they do not rise) echoes the protection of the priestly office itself. Those who opposed Levi's ministry — as Korah (Num 16), Saul (1 Sam 13), Uzziah (2 Chr 26) — would find their opposition divinely crushed.</p>",
        "12": "<p><strong>lĕḇinyāmîn ʾāmar yĕdîd YHWH yiškōn lāḇeṭaḥ ʿālāyw</strong> — 'Of Benjamin he said: The beloved of YHWH dwells in safety beside him.' <em>Yĕdîd YHWH</em> (beloved of YHWH — H3039 from H1730, love) gives Benjamin YHWH's personal affection — the tribe that would carry the temple in Jerusalem on its territory. <em>Yiškōn lāḇeṭaḥ ʿālāyw</em> (he dwells in security beside him) and <em>ḥōpēp ʿālāyw kol-hayyôm</em> (he covers/shields him all the day long) and <em>ûḇên kĕtēpāyw šākhēn</em> (he dwells between his shoulders/flanks) — the last phrase locates YHWH's dwelling between Benjamin's mountain ridges, anticipating the Jerusalem temple which sat on the Benjamin-Judah border.</p>",
        "13": "<p><strong>ûlĕyôsēp ʾāmar mĕḇōreket YHWH ʾartsô</strong> — 'Of Joseph he said: Blessed by YHWH is his land.' Joseph's blessing is the most lavishly detailed, covering geography (heavens, earth, depths), time (perennial fruit, every month), and cosmic abundance. <em>Mimmeghed šāmayim miṭṭāl</em> (from the bounty of heaven's dew), <em>ûmittĕhôm rōḇetset tāḥat</em> (from the deep lying beneath) — the blessing comes from above (rain/dew) and below (springs/groundwater). The fertile Manasseh and Ephraim territories in the central highlands (modern West Bank and Jezreel Valley) were indeed among the most productive agricultural regions in Canaan.</p>",
        "14": "<p><strong>ûmimmeghed tĕḇûʾōt šāmeš</strong> — 'From the bounty of the produce of the sun.' The solar blessing (<em>tĕḇûʾōt šāmeš</em> — sun-ripened harvest) and lunar blessing (<em>meghed garēš yĕrāḥîm</em> — bounty yielded by the moon) refer to the agricultural rhythms governed by celestial bodies. The complete round of the agricultural year — spring rains from the heavens, summer sun ripening, autumn harvest, winter depths supplying groundwater — was YHWH's gift to Joseph's land. The verse reflects sophisticated agricultural understanding: both solar radiation for ripening and lunar cycles governing tidal/rainfall patterns contributed to the land's productivity.</p>",
        "15": "<p><strong>ûmerōʾš harĕrê-qedem ûmimmeghed giḇĕʿôt ʿôlām</strong> — 'From the finest of the ancient mountains, the bounty of the age-old hills.' The mountains (<em>harĕrê-qedem</em> — ancient mountains, from the beginning of time) and everlasting hills (<em>giḇĕʿôt ʿôlām</em>) provided the mineral richness and forest resources that supplemented the valley agriculture. The phrase echoes Gen 49:26 (Jacob's blessing of Joseph: 'bounties of the ancient mountains, the age-old hills'). The geologically ancient landscape of Canaan — limestone ridges, fertile valleys, springs — was Joseph's inheritance, and its abundance was traced to YHWH's creation of the land from primordial times.</p>",
        "16": "<p><strong>ûmimmeghed ʾerets ûmĕlôʾāh ûrĕtsôn šōkhĕnî sĕneh</strong> — 'From the bounty of the earth and its fullness, and from the favor of the one who dwelt in the bush.' The reference to <em>šōkhĕnî sĕneh</em> (the dweller in the bush — H5572, the burning bush of Exod 3) is extraordinary: YHWH appeared to Moses in the thorn-bush of the desert, and this theophany on behalf of Joseph's tribes is now invoked for their blessing. The connection: YHWH met Moses in the wilderness to announce Israel's redemption from Egypt — that same divine favor (<em>rĕtsôn</em> — H7522, favor, goodwill, acceptable pleasure) would rest on Joseph's territory. The theophany-blessing connection honored both the means of Exodus revelation and its beneficiaries.</p>",
        "17": "<p><strong>bekôr šôrô hādār lô weqarnê rĕʾēm qarnāyw</strong> — 'A firstborn bull — majesty is his! His horns are the horns of a wild ox.' The bull-imagery for Ephraim (<em>šôr</em> — H7794, bull/ox, symbol of power and agricultural strength) was YHWH's chosen imagery for Joseph's supremacy. <em>Rĕʾēm</em> (H7214 — wild ox, the aurochs, the most formidable bovine) with its <em>qarnāyw</em> (horns — H7161) would gore (<em>yenaggaḥ</em>) peoples together. The military application: <em>ʾappê-ʾereṣ yaḥdāw</em> (pushing the peoples to the ends of the earth). The ten thousands of Ephraim (<em>rĕḇāḇôt ʾeprayim</em>) and the thousands of Manasseh (<em>ʾalpê manašše</em>) were the numerical legacy of Joseph's blessing — the largest tribal census counts in Num 1 and 26.</p>",
        "18": "<p><strong>ûlizĕḇûlun ʾāmar śĕmaḥ zĕḇûlun bĕṣēʾtekhā</strong> — 'Of Zebulun he said: Rejoice, Zebulun, in your going out.' The twin blessing of Zebulun and Issachar (Gen 49:13-14) reflects their geographic and economic partnership: Zebulun's <em>bĕṣēʾtekhā</em> (going out — maritime/trade ventures) and Issachar's <em>bĕʾohālêkhā</em> (in your tents — agricultural stability). The pairing celebrates the complementarity of trade and farming: Zebulun's sea commerce (<em>yirʾû</em> — they will suck the wealth of the sea) and Issachar's land productivity. The reference to <em>safûn yammîm</em> (the hidden treasures of the sand) likely refers to glassmaking sand from the Carmel coast, an important trade commodity in antiquity.</p>",
        "19": "<p><strong>ʿammîm har-yiqrāʾû šāmmāh yizbeḥû ziḇḥê-tsedeq</strong> — 'They will summon peoples to the mountain; there they will offer right sacrifices.' The mountain (<em>har</em>) where peoples are summoned to worship anticipates Zion theology (Isa 2:3; Mic 4:2 — 'let us go up to the mountain of YHWH'). <em>Ziḇḥê-tsedeq</em> (sacrifices of righteousness — H6664) are the properly offered, covenantally correct sacrifices (cf. Ps 4:5; 51:19). The Zebulun-Issachar region sucked the wealth of the seas (<em>šĕfaq yammîm yinyaqû</em>) and the hidden treasures of the sand (<em>ûśĕfûnê tĕmûnê ḥôl</em>) — indicating a prosperous region that would support proper worship.</p>",
        "20": "<p><strong>ûlĕgād ʾāmar bārûkh marḥîḇ gād</strong> — 'Of Gad he said: Blessed is he who enlarges Gad.' The blessing for Gad emphasizes territorial expansion (<em>marḥîḇ</em> — H7337, to widen, enlarge) and military prowess: Gad dwells like a lion (<em>kĕlāḇîʾ šākhēn</em>), tearing arm and crown of the head (<em>veyiṭrap zĕrôaʿ ʾap-qodqōd</em>). The verb <em>ṭārap</em> (H2963 — to tear, rend — the lion's attack) portrays Gad as a fierce warrior tribe. The first portion (<em>rēʾšît lô</em>) was taken for Gad — possibly referring to their early conquest east of the Jordan (Num 32) or the firstfruits of the spoil. Gad's territory in Gilead was frontier land requiring both military strength and territorial aggression.</p>",
        "21": "<p><strong>vayyarʾ rēʾšît lô kî šām ḥelqat mĕḥōqēq sāfûn</strong> — 'He chose the best land for himself, for a commander's portion was reserved for him.' <em>Mĕḥōqēq</em> (H2710 — lawgiver, commander, the one who enacts decrees) in Gad's territory may allude to Moses's burial there (Deut 34:6 — on the east side of the Jordan) or to a leader born from Gad. The verse ends with praise: <em>wayyēṯē rāʾšê ʿām tsidqat YHWH weʾet-mišpāṭāyw ʿim-yisrāʾel</em> (he came with the heads of the people, executed YHWH's righteousness and his ordinances with Israel). Gad's loyalty to the trans-Jordan covenant commitment (Josh 22) validated this blessing.</p>",
        "22": "<p><strong>ûlĕdān ʾāmar dān gûr ʾaryēh yĕzanneq min-habbāšān</strong> — 'Of Dan he said: Dan is a lion's cub that leaps from Bashan.' The Dan blessing uses the lion-cub imagery (<em>gûr ʾaryēh</em> — H1482 gûr, young animal; H738 ʾaryēh, lion) that Gen 49:9 applied to Judah. Dan's migration from their original southern allotment to Bashan in the far north (Judg 17-18) was apparently anticipated here — the tribe that leapt northward to find new territory. <em>Yĕzanneq</em> (H2187 — to leap, spring — a hapax legomenon) suggests sudden movement. Dan's military agility and territorial flexibility made them a distinct tribe, though their ultimate apostasy (setting up idols at Laish/Dan) was the shadow over their blessing.</p>",
        "23": "<p><strong>ûlĕnaptālî ʾāmar naptālî śĕbaʿ rātsôn ûmālēʾ birkhat YHWH</strong> — 'Of Naphtali he said: Naphtali, satisfied with favor, full of the blessing of YHWH.' The three-fold abundance: <em>śāḇaʿ rātsôn</em> (satisfied with favor — H7646, H7522), <em>mālēʾ birkhat YHWH</em> (full of YHWH's blessing — H4390), and possession of <em>yam wedarôm yrāšāh</em> (the sea and the south take possession). The 'sea' likely refers to the Sea of Galilee (Kinneret) on Naphtali's western border, and the 'south' to its territory extending southward. Naphtali's territory included some of the most fertile land in the Galilee region — the Kinnereth basin, source of abundant fish and agricultural produce.</p>",
        "24": "<p><strong>ûlĕʾāšēr ʾāmar bārûkh mibbānîm ʾāšēr</strong> — 'Of Asher he said: Most blessed of sons is Asher.' Asher's blessing is triple: most blessed among sons (<em>bārûkh mibbānîm</em>), favored by brothers (<em>yĕhî rĕtsûy ʾeḥāyw</em>), and destined to dip his foot in oil (<em>weṭōḇēl bašemen raglô</em>). The olive oil (<em>šemen</em>) for which the Asher coastal territory was famous (the modern Carmel coast and western Galilee) is legendary — still today the finest olives in the region grow along this coast. The combination of material prosperity (<em>barezel ûnĕḥōšet</em> — iron and bronze sandals for strength, v25) and covenant security made Asher's tribal portion one of the most desirable.</p>",
        "25": "<p><strong>barzel ûnĕḥōšet mĕnaʿălêkhā ûkeḏāḇrekhā yaḏmôtekhā</strong> — 'Your bars shall be iron and bronze; as your days, so your strength.' The promise to Asher has two parts: <em>barzel ûnĕḥōšet mĕnaʿălêkhā</em> (iron and bronze are your shoes/bolts — either sandals or door-bolts, symbolizing impregnable defense) and <em>keḏāḇrekhā yaḏmôtekhā</em> (as your days, so your strength — literally 'as your day, so your rest/security'). The formula <em>keḏāḇrekhā</em> (as your day) means: whatever each day demands, YHWH provides the corresponding strength. This promise was later universalized by Paul (Phil 4:19: 'my God will supply every need of yours according to his riches in glory') and is the model for covenant sufficiency.</p>",
        "28": "<p><strong>wayyiškōn yisrāʾēl beṭaḥ bādād ʿên yaʿăqōḇ</strong> — 'Israel lived in safety, Jacob in security alone.' The closing vision of Israel's blessed state: <em>beṭaḥ bādād</em> (in security, alone — H983, H910) — the security of those who need no international alliances, dwelling safely because YHWH alone is their protector. The phrase <em>ʾên yaʿăqōḇ</em> (the spring/eye of Jacob) is ambiguous but likely refers to YHWH as the living spring sustaining Jacob. The agricultural bounty: <em>ʾel ʾereṣ dāgān wĕṯîrôš</em> (to a land of grain and new wine), <em>ʾap-šāmāyw yaʿărpû ṭāl</em> (whose heavens drip with dew). The land is the material expression of YHWH's covenant faithfulness to the patriarchal promises.</p>",
        "29": "<p><strong>ʾašrêkhā yisrāʾēl mî khāmôkhā</strong> — 'Blessed are you, O Israel! Who is like you?' The macarism (<em>ʾašrêkhā</em> — H835, blessed, happy — the plural of fullness, comprehensive wellbeing) closes the entire blessing collection. The rhetorical question <em>mî khāmôkhā</em> (who is like you?) echoes Exod 15:11 (<em>mî khāmōkhā bāʾēlim YHWH</em> — who is like you among the gods, O YHWH) — Israel's uniqueness mirrors YHWH's uniqueness: both are incomparable in their respective spheres. The reason: <em>ʿam nôšaʿ baYHWH</em> (a people saved by YHWH) and <em>māgēn ʿezrekā</em> (shield of your help) and <em>ʾăšer-ḥereb gaʾwātekā</em> (the sword of your majesty). Israel's greatness was entirely derivative — it was great because its God was great, saved because its Savior was YHWH.</p>",
    },
    "34": {
        "1": "<p><strong>vayyaʿal mōšeh mēʿarḇōt môʾāḇ ʾel-har nĕḇô</strong> — 'Moses went up from the plains of Moab to Mount Nebo.' The final ascent: <em>ʿarḇôt môʾāḇ</em> (plains of Moab — the trans-Jordanian plateau where Israel had camped), <em>har nĕḇô</em> (Mount Nebo — the peak of the Abarim range). The peak (<em>rōʾš happisgāh</em> — the summit of Pisgah — H6449, a ridge of the Abarim range) is specified, confirming the view-angle toward the west. The land Moses saw: <em>gilʿād ʿad-dān</em> (Gilead to Dan — the northern Jordan River region), comprising the entire visible extent of the promised land. The Chronicler of Moses's death presents it as a farewell vision — the final gift of seeing what he could not enter.</p>",
        "2": "<p><strong>weʾēt kol-naptālî weʾet-ʾerets ʾeprayim ûmanašše</strong> — 'And all of Naphtali, the land of Ephraim and Manasseh.' The panoramic list continues: Naphtali's territory in upper Galilee, Ephraim and Manasseh's central hill country, Judah's territory to the western sea (<em>ʾel-hayyām hāʾaḥărôn</em> — to the Mediterranean), the Negev (<em>hannegev</em>), and the Plain of Jericho (<em>kikkar biqʿat yĕrîḥô</em>) to Zoar. The completeness of the vision — from north to south, from east to west — confirms that Moses saw the entire promised inheritance. The vision was not partial but comprehensive: YHWH gave Moses the full inheritance in sight even when denying him the full inheritance in body.</p>",
        "3": "<p><strong>weʾet-hannegev weʾet-hakkikkār gê yĕrîḥô</strong> — 'The Negev and the Plain, the valley of Jericho, the city of palms, as far as Zoar.' The southern extent: <em>hannegev</em> (the Negev wilderness), <em>kikkār gê yĕrîḥô</em> (the plain/circle of the valley of Jericho — the Jordan valley floor, one of the lowest points on earth), <em>ʿîr hattĕmārîm</em> (city of palms = Jericho, famous for its date palm groves), and <em>ṣōʿar</em> (Zoar — the small city spared in Lot's escape from Sodom, Gen 19:22, at the southern end of the Dead Sea). The complete circuit — from Dan in the north to Zoar in the south — gave Moses a comprehensive survey of the covenant inheritance.</p>",
        "4": "<p><strong>vayyōʾmer YHWH ʾēlāyw zōʾt hāʾārets ʾăšer nišbaʿtî lĕʾaḇrāhām lĕyitsḥāq ûlĕyaʿăqōḇ</strong> — 'YHWH said to him: This is the land I swore to Abraham, Isaac, and Jacob.' The divine speech at the moment of death is YHWH's fulfillment declaration: the land Moses saw was the land of the Abrahamic oath (Gen 12:7; 15:18-21; 17:8; 26:3; 28:13-15). <em>Nišbaʿtî lĕʾaḇrāhām</em> (I swore to Abraham — the Patriarchal covenant) was the legal foundation of Israel's claim to Canaan. The inclusion of all three patriarchal names confirms the covenant's intergenerational continuity: the oath to Abraham was renewed with Isaac and Jacob, creating an unbroken chain of divine commitment. Moses's death did not invalidate the oath — Joshua would carry out what Moses viewed.</p>",
        "5": "<p><strong>vayyāmot šāmmāh mōšeh ʿeḇed-YHWH bĕʾerets môʾāḇ</strong> — 'Moses died there, the servant of YHWH, in the land of Moab.' The death of Moses is recorded with the title <em>ʿeḇed YHWH</em> (servant of YHWH — H5650, H3068) — the highest possible title in Israel's prophetic tradition. <em>ʿEḇed YHWH</em> would become the name of the Suffering Servant of Isaiah 40-55, the one who would perfectly fulfill what Moses foreshadowed. Moses died <em>ʿal-pî YHWH</em> (by the mouth/command of YHWH — literally 'by the mouth of YHWH'; a rabbinic tradition read this as 'by a divine kiss'). The location — Moab, east of the Jordan — meant Moses died having completed his mission but not entered his reward: the model of the servant who gives everything without personal benefit.</p>",
        "7": "<p><strong>ûmōšeh ben-meʾāh weʿeśrîm šānāh bĕmōtô</strong> — 'Moses was 120 years old when he died.' The triple structure of Moses's life was recognized in ancient Jewish tradition: 40 years in Egypt, 40 years in Midian, 40 years in the wilderness (Acts 7:23,30,36). The triple perfection (3 × 40) of Moses's 120-year lifespan made his biography a symbol of completeness. <em>Lōʾ-khāhătāh ʿênô welōʾ-nās lēḥōh</em> (his eye was not dim nor had his vigor diminished) — a physiological statement that Moses's death was not from natural decline but from divine appointment. His capacities were fully intact at death — making his inability to enter the land a matter of divine decision, not incapacity.</p>",
        "8": "<p><strong>vayyiḇkû ḇnê yisrāʾēl ʾet-mōšeh bĕʿarḇōt môʾāḇ šlōšîm yôm</strong> — 'The sons of Israel wept for Moses in the plains of Moab for thirty days.' The mourning period: <em>šelōšîm yôm</em> (thirty days) was the standard royal and prophetic mourning period (cf. Aaron's thirty days in Num 20:29; Saul in 1 Sam 31:13 with seven days). The phrase <em>vayyitmĕû yĕmê vekhi ʾēbel mōšeh</em> (the days of weeping and mourning for Moses were completed) closes the era with formal grief. Moses was mourned as Israel's founder-prophet — the one through whom the nation had been constituted at Sinai. The thirty-day mourning equated Moses with Aaron, honoring both pillars of the wilderness leadership equally in death.</p>",
        "9": "<p><strong>wîhôšuaʿ bin-nûn māleʾ rûaḥ ḥokhmāh</strong> — 'Joshua son of Nun was full of the spirit of wisdom.' The transition: <em>rûaḥ ḥokhmāh</em> (spirit of wisdom — H7307, H2451) was imparted to Joshua when Moses laid hands on him (<em>kî-sāmakh mōšeh ʾet-yādāyw ʿālāyw</em> — because Moses had laid his hands on him). The spirit of wisdom for governance was distinct from the prophetic spirit — it equipped Joshua for the specific task of conquest administration and tribal distribution. <em>Vayyišmĕʿû ʾēlāyw bĕnê yisrāʾēl</em> (the sons of Israel obeyed him) — the leadership transfer was complete and accepted. YHWH's command to obey Joshua (Josh 1:16-18) was already anticipated in Israel's voluntary submission.</p>",
        "11": "<p><strong>lĕkhol-hāʾōtôt wĕhammôpĕṯîm ʾăšer šĕlaḥô YHWH laʿăśôt bĕʾerets mitsrāyim</strong> — 'For all the signs and wonders YHWH sent him to do in Egypt.' The summary of Moses's unique qualification: the <em>ʾōtôt</em> (signs — H226) and <em>môpĕṯîm</em> (wonders — H4159) in Egypt against Pharaoh (<em>lĕpharʿōh ûlĕkhol-ʿăḇādāyw ûlĕkhol-ʾartsô</em>). The ten plagues, the parting of the Reed Sea, the provision of manna and water — these constituted Moses's prophetic credential. No prophet before or after equaled these signs in scope or directness (<em>lekhol yad hăḥăzāqāh ûlĕkhol hammôrāʾ hāggādōl</em> — all the mighty hand and great terror, v34:12). The conclusion establishes Moses as the unequaled prophet of the Old Covenant, awaiting his antitype.</p>",
        "12": "<p><strong>ûlĕkhol hayyād hahăzāqāh ûlĕkhol hammôrāʾ hāggādôl</strong> — 'And for all the mighty hand and all the great terror that Moses did in the sight of all Israel.' The closing words of the Pentateuch: the mighty hand (<em>yaḏ hahăzāqāh</em> — H3027, H2389) is the formula used for the Exodus deliverance throughout Deuteronomy (4:34; 5:15; 6:21; 7:8; 11:2; 26:8). Moses performed these wonders <em>lĕʿênê kol-yisrāʾēl</em> (in the sight of all Israel) — a public, witnessed, verifiable revelation. The Pentateuch ends where it must: at Moses's death, with the covenant in place, the land in sight, and the prophetic office awaiting its fulfillment. The Mosaic era closes expecting its successor — both the immediate Joshua and the ultimate One of whom Moses said 'YHWH your God will raise up a prophet like me' (Deut 18:15).</p>",
    }
}

def merge_comm(existing, new_data):
    # INTENT: Merge new commentary entries without overwriting existing ones — safe to re-run
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

out_path = pathlib.Path("data/commentary/mkt-original/deuteronomy.json")
existing = json.loads(out_path.read_text()) if out_path.exists() else {}
before = sum(len(existing.get(c, {})) for c in DATA)
merge_comm(existing, DATA)
after = sum(len(existing.get(c, {})) for c in DATA)
out_path.write_text(json.dumps(existing, ensure_ascii=False, indent=2))
print(f"  wrote {out_path}")
print(f"deuteronomy mkt-original: added up to {after - before} verses across ch32-34")
